106	        in_place: &'a mut [MaybeUninit<Self>],
107	        deserializer: &mut ZDeserializer,
108	    ) -> Result<&'a mut [Self], ZDeserializeError> {
109	        default_deserialize_n_uninit(in_place, deserializer)
110	    }
