442	impl<T: Deserialize, const N: usize> Deserialize for [T; N] {
443	    fn deserialize(deserializer: &mut ZDeserializer) -> Result<Self, ZDeserializeError> {
444	        if <VarInt<usize>>::deserialize(deserializer)?.0 != N {
445	            return Err(ZDeserializeError);
446	        }
447	        let mut array = std::array::from_fn(|_| MaybeUninit::uninit());
448	        let slice = T::deserialize_n_uninit(&mut array, deserializer)?;
449	        let (slice_ptr, slice_len) = (slice.as_ptr(), slice.len());
450	        assert_eq!((slice_ptr, slice_len), (array.as_ptr().cast::<T>(), N));
451	        // SAFETY: assertion checks the returned slice is array's one, and it's returned initialized
452	        Ok(array.map(|t| unsafe { t.assume_init() }))
453	    }
454	}
