566	/// The [LEB128](https://en.wikipedia.org/wiki/LEB128) variable-length integer encoding.
567	///
568	/// The `zenoh-ext` implements serialization and deserialization of integers in variable-length `LEB128` format.
569	/// Currently it's implemented for `usize` only using the wrapper struct `VarInt<usize>`:
570	/// the traits [`Serialize`] and [`Deserialize`] are implemented for `VarInt<usize>` using
571	/// [leb128](https://crates.io/crates/leb128) crate.
572	///
573	/// This is used internally for serializing lengths of sequences (slices, `Vec`, `String`, `HashMap`, etc)
574	/// and could be used by users to serialize integer values in a more compact way.
575	#[repr(transparent)]
576	#[derive(Debug, Clone, Copy, PartialEq, Eq, PartialOrd, Ord, Hash)]
577	pub struct VarInt<T>(pub T);
578	impl Serialize for VarInt<usize> {
579	    fn serialize(&self, serializer: &mut ZSerializer) {
580	        leb128::write::unsigned(&mut serializer.0, self.0 as u64).unwrap();
581	    }
582	}
583	impl Deserialize for VarInt<usize> {
584	    fn deserialize(deserializer: &mut ZDeserializer) -> Result<Self, ZDeserializeError> {
585	        let n = leb128::read::unsigned(&mut deserializer.0).or(Err(ZDeserializeError))?;
586	        Ok(VarInt(<usize>::try_from(n).or(Err(ZDeserializeError))?))
587	    }
588	}
589	
590	#[cfg(test)]
591	mod tests {
592	    use std::ops::Range;
593	
594	    use rand::{thread_rng, Rng};
595	
596	    use super::*;
597	
598	    macro_rules! serialize_deserialize {
599	        ($ty:ty, $expr:expr) => {
600	            let expr: &$ty = &$expr;
601	            let payload = z_serialize(expr);
602	            let output = z_deserialize::<$ty>(&payload).unwrap();
603	            assert_eq!(*expr, output);
604	        };
605	    }
606	
607	    const RANDOM_TESTS: Range<usize> = 0..1_000;
608	
609	    #[test]
610	    fn numeric_serialization() {
611	        macro_rules! test_int {
612	            ($($ty:ty),* $(,)?) => {$(
613	                serialize_deserialize!($ty, <$ty>::MIN);
614	                serialize_deserialize!($ty, <$ty>::MAX);
615	                let mut rng = thread_rng();
616	                for _ in RANDOM_TESTS {
617	                    serialize_deserialize!($ty, rng.gen::<$ty>());
618	                }
619	            )*};
620	        }
621	        test_int!(i8, i16, i32, i64, i128, u8, u16, u32, u64, u128, f32, f64);
622	    }
623	
624	    #[test]
625	    fn varint_serialization() {
626	        serialize_deserialize!(VarInt<usize>, VarInt(<usize>::MIN));
627	        serialize_deserialize!(VarInt<usize>, VarInt(<usize>::MAX));
628	        let mut rng = thread_rng();
629	        for _ in RANDOM_TESTS {
630	            serialize_deserialize!(VarInt<usize>, VarInt(rng.gen::<usize>()));
631	        }
632	    }
633	
634	    #[test]
635	    fn primitive_slice_serialization() {
636	        let vec = vec![42.0f64, 0.15];
637	        serialize_deserialize!(Vec<f64>, vec);
638	        let payload = z_serialize(vec.as_slice());
639	        assert_eq!(vec, z_deserialize::<Vec<f64>>(&payload).unwrap())
640	    }
641	
642	    #[test]
643	    fn slice_serialization() {
644	        let vec = vec!["abc".to_string(), "def".to_string()];
645	        serialize_deserialize!(Vec<String>, vec);
646	        let payload = z_serialize(vec.as_slice());
647	        assert_eq!(vec, z_deserialize::<Vec<String>>(&payload).unwrap())
648	    }
649	
650	    #[test]
651	    fn string_serialization() {
652	        let s = "serialization".to_string();
653	        serialize_deserialize!(String, s);
654	        let payload = z_serialize(s.as_str());
655	        assert_eq!(s, z_deserialize::<String>(&payload).unwrap())
656	    }
657	
658	    #[test]
659	    fn tuple_serialization() {
660	        serialize_deserialize!(
661	            (VarInt<usize>, f32, String),
662	            (VarInt(42), 42.0f32, "42".to_string())
663	        );
664	    }
665	
666	    #[test]
667	    fn hashmap_serialization() {
668	        let mut map = HashMap::new();
669	        map.insert("hello".to_string(), "world".to_string());
670	        serialize_deserialize!(HashMap<String, String>, map);
671	    }
672	
673	    macro_rules! check_binary_format {
674	        ($expr:expr, $out:expr) => {
675	            let payload = z_serialize(&$expr);
676	            assert_eq!(payload.to_bytes(), $out);
677	        };
678	    }
679	
680	    #[test]
681	    fn binary_format() {
682	        let i1: i32 = 1234566;
683	        check_binary_format!(i1, vec![134, 214, 18, 0]);
684	        let i2: i32 = -49245;
685	        check_binary_format!(i2, vec![163, 63, 255, 255]);
686	        let s: &str = "test";
687	        check_binary_format!(s, vec![4, 116, 101, 115, 116]);
688	        let t: (u16, f32, &str) = (500, 1234.0, "test");
689	        check_binary_format!(t, vec![244, 1, 0, 64, 154, 68, 4, 116, 101, 115, 116]);
690	        let v: Vec<i64> = vec![-100, 500, 100000, -20000000];
691	        check_binary_format!(
692	            v,
693	            vec![
694	                4, 156, 255, 255, 255, 255, 255, 255, 255, 244, 1, 0, 0, 0, 0, 0, 0, 160, 134, 1,
695	                0, 0, 0, 0, 0, 0, 211, 206, 254, 255, 255, 255, 255
696	            ]
